class Solution {
public:
    bool hasPathSum(TreeNode* root, int target) {
        if (!root) return false;
        if (!root->left && !root->right) return root->val == target;
        int rem = target - root->val;
        return hasPathSum(root->left, rem) || hasPathSum(root->right, rem);
    }
};
